async function seed() {
  await mongoose.connect(process.env.MONGO_URI);
  console.log('Connected to MongoDB');

  await Lesson.deleteMany();
  await Quiz.deleteMany();
  await Challenge.deleteMany();

  const createdLessons = await Lesson.insertMany(lessons);
  console.log(createdLessons.length + ' lessons seeded');

  const quizDocs = quizzes.map(function(q) {
    return {
      lessonId: createdLessons[q.lessonIndex] ? createdLessons[q.lessonIndex]._id : createdLessons[0]._id,
      title: q.title,
      points: q.points,
      questions: q.questions,
    };
  });
  await Quiz.insertMany(quizDocs);
  console.log(quizDocs.length + ' quizzes seeded');

  await Challenge.insertMany(challenges);
  console.log(challenges.length + ' challenges seeded');

  const existing = await User.findOne({ email: 'admin@ecoverse.com' });
  if (!existing) {
    await User.create({ name: 'Admin', email: 'admin@ecoverse.com', password: 'admin123', role: 'admin' });
    console.log('Admin created: admin@ecoverse.com / admin123');
  }

  console.log('Seed complete!');
  process.exit(0);
}

seed().catch(function(err) { console.error(err); process.exit(1); });
